import dayjs from "dayjs";

export const getPageType = (isThisWeek: boolean, date: string) => {
  if (date) {
    return isThisWeek
      ? "周末查漏补缺任务"
      : dayjs().isAfter(dayjs(date).endOf("week"))
        ? "本周查漏补缺任务"
        : "下周查漏补缺任务"
  } else {
    return isThisWeek
      ? "周末查漏补缺任务"
      : dayjs().day() === 0
        ? "下周查漏补缺任务"
        : "本周查漏补缺任务"
  }
}


export const getRangeStartDate = (isThisWeek: boolean, date: string) => {

  if (date) {

    if (isThisWeek) {
      // 一周从周一开始
      return dayjs(date).startOf('week').add(4, 'day');
    } else {
      return dayjs(date).startOf('week').add(6, 'day')
    }
  } else {
    if (isThisWeek) {
      // 一周从周一开始
      return dayjs().startOf("week").add(4, "days");
    } else {
      // 下周查漏补缺任务，窗口期是周日晚8点半到下周五晚7点之间，返回周日
      if (dayjs().day() === 0) {
        return dayjs().startOf("week").add(6, "days");
      } else {
        return dayjs().startOf("week").subtract(1, "days");
      }
    }
  }
};

export const timeFormat = (time: number, type = 'YMD') => {
  if (time === 0) return '---';
  const date = new Date(time);
  const year = date.getFullYear();
  const month = date.getMonth() + 1;
  const day = date.getDate();
  const dayOfWeek = ['日', '一', '二', '三', '四', '五', '六'][date.getDay()];

  switch (type) {
    case 'YMD':
      return `${year}年${month}月${day}日`;
    case 'YM':
      return `${year}年${month}月`;
    case 'MD':
      return `${month}月${day}日`;
    case 'YMDW':
      return `${year}年${month}月${day}日 周${dayOfWeek}`;
    case 'MDW':
      return `${month}月${day}日 周${dayOfWeek}`;
    default:
      return '';
      break;
  }
};

export const timeRangeFormat = (startTime: number, endTime: number) => {
  const startDate = new Date(startTime);
  const endDate = new Date(endTime);

  const s_year = startDate.getFullYear();
  const s_month = startDate.getMonth() + 1;
  const s_day = startDate.getDate();
  const s_dayOfWeek = ['日', '一', '二', '三', '四', '五', '六'][
    startDate.getDay()
  ];

  const e_year = endDate.getFullYear();
  const e_month = endDate.getMonth() + 1;
  const e_day = endDate.getDate();
  const e_dayOfWeek = ['日', '一', '二', '三', '四', '五', '六'][
    endDate.getDay()
  ];

  if (s_year === e_year && s_month === e_month && s_day === e_day) {
    return `${s_month}月${s_day}日`;
  }

  if (s_year === e_year) {
    return `${s_month}月${s_day}日-${e_month}月${e_day}日`;
  }

  if (s_year !== e_year) {
    return `${(s_year + '').slice(2)}年${s_month}月${s_day}日-${(
      e_year + ''
    ).slice(2)}年${e_month}月${e_day}日`;
  }
};


export const getTotalMin = (arr: any[]) => {
  return arr.reduce((prev: number, cur: any) => {
    return prev + cur.learn_time;
  }, 0);
};

export const getHourAndMin = (totalMin: number) => {
  return { h: Math.floor(totalMin / 60), m: totalMin % 60 };
};


export const getDisplayTime = (h: number, m: number) =>
  `${h > 0 ? h + "小时" : ""}${m > 0 ? m + "分钟" : ""}`;

