import dayjs from 'dayjs';
import 'dayjs/locale/zh-cn'; // 导入中文语言包
dayjs.locale('zh-cn'); // 使用中文语言

export const getDates = (taskList: any) => {
  const Dates: number[] = []
  taskList.forEach((task: any) => {
    const startTime = +new Date(dayjs.unix(task.start_time).format('YYYY-MM-DD'))
    const endTime = +new Date(dayjs.unix(task.end_time).format('YYYY-MM-DD'))

    Dates.push(startTime)
    Dates.push(endTime)
    // 把时间段内的日期都加入到Dates数组中
    if (startTime !== endTime) {
      const days = Math.floor((endTime - startTime) / (24 * 3600 * 1000))
      for (let i = 1; i <= days; i++) {
        const date = startTime + i * 24 * 3600 * 1000
        Dates.push(date)
      }
    }
  })
  // console.log('getDates', Dates)
  // 去重
  const uniqueArr = Array.from(new Set(Dates))

  console.log('去重后的数组', uniqueArr)
  // 排序
  const sortedDates = [...uniqueArr].sort((a: number, b: number) => a - b);
  // console.log('排序后的数组', sortedDates)
  return sortedDates
}
export const getWeeks = (dates: any) => {
  const weeks: string[] = []
  dates.forEach((date: string) => {
    weeks.push(`周${dayjs(date).format('dd')}`)
  })
  // console.log('getWeeks', weeks) ['周五', '周日']
  return weeks
}
export const getDays = (dates: any) => {
  const weekDays: string[] = []
  dates.forEach((date: string) => {
    weekDays.push(dayjs(date).format('M月D日'))
  })
  console.log('getWeekDays', weekDays) // ['3月8日', '3月10日']
  return weekDays
}

export const areDatesConsecutive = (dates: any) => {
  if (dates.length === 1) {
    return false; // 如果只有一个日期，返回false
  }
  // 检查是否为连续日期
  for (let i = 1; i < dates.length; i++) {
    const currentDate = dates[i];
    const previousDate = dates[i - 1];
    if (+new Date(currentDate).getDate() - +new Date(previousDate).getDate() !== 1) {
      return false; // 如果不是连续的，返回false
    }
  }
  return true; // 如果是连续的，返回true
}
// 获取周日23:59:59的时间戳
export const getSundaytimestamp = (s: string) => {
  // const MondayTime = new Date(`${s} 00:00:00`).getTime()
  // const SundayTime = MondayTime + 7 * 24 * 60 * 60 * 1000 - 1
  const getTimestamp = new Date(`${s} 00:00:00`).getTime()
  // // 周日23:59:59的时间戳
  const SundayTime = getTimestamp + (8 - dayjs(s).day()) * 24 * 60 * 60 * 1000 - 1
  console.log(SundayTime, 'SundayTime', dayjs(SundayTime).format('MM-DD HH:mm:ss'))
  return SundayTime
}
// 是否在本周内
export const isThisWeek = (DateVal: string) => {
  if (!DateVal) {
    return true
  }
  const SundayTime = getSundaytimestamp(DateVal)
  return new Date().getTime() <= SundayTime
}