import sensors from "@/utils/sensors";
import { useRoute } from "vue-router";
import dayjs from "dayjs";
import { getPageType, getRangeStartDate } from './utils'
// 私有变量
let defaultConfig = {}

function useTrack() {
    const {
        query: { type = "1",
            date, },
    } = useRoute();
    const isThisWeek = type === "1"; // 两种：1 为周末查漏补缺任务 2 下周查漏补缺任务
    const rangeStartDate = getRangeStartDate(isThisWeek, date as string);

    const track = (type: string, obj = {}) => {
        sensors.track(type, {
            page_type: getPageType(isThisWeek, date as string),
            produce_date: rangeStartDate.format("YYYY-MM-DD"),
            ...defaultConfig,
            ...obj,
        });
    };
    const setDefaultConfig = (obj: any) => {
        defaultConfig = obj
    }

    return {
        track,
        setDefaultConfig
    };
}

export default useTrack;

