import { defineStore } from 'pinia'
import { ref } from 'vue'
export const useTaskerStore = defineStore('tasker', () => {
  const choosedTaskArr = ref([])
  // 打点需要初始的默认选中的任务
  const defChoosedTaskList = ref([])
  // 加载出来任务总数
  const loadedTaskListCount = ref(0)
  const reportDate = ref('')
  const setTaskArr = (taskList: []) => {
    choosedTaskArr.value = Array.isArray(taskList) ? taskList : []
  }
  const setDate = (val: string) => {
    reportDate.value = val
  }
  const setDefChoosedTaskList = (taskList: []) => {
    defChoosedTaskList.value = Array.isArray(taskList) ? taskList : []
  }
  const setLoadedTaskListCount = (count: number) => {
    loadedTaskListCount.value = count
  }
  return {
    choosedTaskArr,
    setTaskArr,
    reportDate,
    setDate,
    defChoosedTaskList,
    setDefChoosedTaskList,
    loadedTaskListCount,
    setLoadedTaskListCount,
  }
})
